#include<bits/stdc++.h>
using namespace std;
long long n, k, a[50005], i = 1, j = 2, ans = 0, b[50005], ans2 = 0;
int main() {
	cin >> n >> k;
	for (int i = 1; i <= n; i++) cin >> a[i];
	a[n + 1] = INT_MAX;
	sort(a + 1, a + 1 + n);
	while (i <= n) {
		while (a[j] <= a[i] + k) j++;
		b[j] = max(j - i, b[j]);
		ans2 = max(ans2, b[i]);
		ans = max(ans, ans2 + j - i);
		i++;
	}
	cout << ans;
	return 0;
}
